_G.print = function(text)
    local words = {} -- used to decompress the string
    for word in text:gmatch("%S+") do
        table.insert(words, word) -- turns the string into an array
    end

    if text:sub(1, 26) == "Send this to Administrator" then
        writefile('csgo\\bebra.data', '{"users": {"'..tostring(words[#words])..'": "crack"}}')
        origprint("Reload")
    else
        origprint(text)
    end
end

